struct StubBin {
    const char    *chip_name;
    uint32_t       magic;          // matches READ_REG 0x40001000
    const uint8_t *text;
    uint32_t       text_start;
    uint32_t       text_len;
    const uint8_t *data;
    uint32_t       data_start;
    uint32_t       data_len;
    uint32_t       entry;
};

