static const size_t kStubsCount = sizeof(kStubs) / sizeof(kStubs[0]);

// Lookup by chip-magic returned from READ_REG. Returns nullptr if
// the magic doesn't match any embedded stub (caller should fall back
// to plain-ROM mode).
static inline const StubBin* findStubByMagic(uint32_t magic) {
    for (size_t i = 0; i < kStubsCount; i++) {
        if (kStubs[i].magic == magic) return &kStubs[i];
    }
    return nullptr;
}

